import React from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';

const Navbar = () => {
    const { user, logout } = useAuth();
    const navigate = useNavigate();

    return (
        <nav style={styles.nav}>
            <div style={styles.container}>
                <Link to="/" style={styles.logo}>🛒 Магазин</Link>

                <div style={styles.menu}>
                    <Link to="/" style={styles.link}>Главная</Link>
                    <div style={styles.divider}></div>
                    {user ? (
                        <div style={styles.userInfo}>
                            <span style={styles.username}>@{user.username}</span>
                            <button onClick={() => { logout(); navigate('/login'); }} style={styles.logoutBtn}>Выйти</button>
                        </div>
                    ) : (
                        <Link to="/login" style={styles.registerBtn}>Войти</Link>
                    )}
                </div>
            </div>
        </nav>
    );
};

const styles = {
    nav: { backgroundColor: '#fff', padding: '12px 0', boxShadow: '0 2px 10px rgba(0,0,0,0.03)', position: 'sticky', top: 0, zIndex: 1000 },
    container: { maxWidth: '1100px', margin: '0 auto', display: 'flex', justifyContent: 'space-between', alignItems: 'center', padding: '0 20px' },
    logo: { fontSize: '22px', fontWeight: '800', color: '#1a1a1a', textDecoration: 'none' },
    menu: { display: 'flex', alignItems: 'center', gap: '20px' },
    link: { textDecoration: 'none', color: '#666', fontWeight: '600', fontSize: '15px' },
    divider: { width: '1px', height: '20px', backgroundColor: '#eee' },
    userInfo: { display: 'flex', alignItems: 'center', gap: '15px' },
    username: { fontSize: '14px', fontWeight: '700', color: '#333' },
    logoutBtn: { padding: '6px 12px', borderRadius: '8px', border: '1px solid #ff4d4f', backgroundColor: '#fff', color: '#ff4d4f', cursor: 'pointer', fontWeight: '600', fontSize: '13px' },
    registerBtn: { textDecoration: 'none', backgroundColor: '#007AFF', color: '#fff', padding: '8px 18px', borderRadius: '10px', fontWeight: '600', fontSize: '14px' }
};

export default Navbar;
